#include <stdio.h>
#include <string.h>

int max(int a, int b) {
    return (a > b) ? a : b;
}

int main() {
    char s[1001], t[1001];  // Assuming the maximum length of the string is 1000
    scanf("%s", s);

    int n = strlen(s);

    // Create the reversed string t
    for(int i = 0; i < n; i++) {
        t[i] = s[n - 1 - i];
    }
    t[n] = '\0';  // Null-terminate the reversed string

    // Length of the longest palindromic subsequence will be 
    // the Longest common subsequence of a string with 
    // reverse of itself

    int dp[n + 1][n + 1];

    for(int i = 0; i <= n; i++) {
        // Base cases
        dp[i][0] = 0;
        dp[0][i] = 0;
    }

    for(int i = 1; i <= n; i++) {
        for(int j = 1; j <= n; j++) {
            // Dp transitions
            if (s[i - 1] == t[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
            }
        }
    }

    printf("%d\n", dp[n][n]);
    return 0;
}

