import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();

        String t = new StringBuilder(s).reverse().toString();

        /*
        Length of the longest palindromic subsequence will be 
        the Longest common subsequence of a string with 
        the reverse of itself
        */

        int n = s.length();
        int m = t.length();

        int[][] dp = new int[n + 1][m + 1];

        for (int i = 0; i <= n; i++) {
            // Base cases
            dp[i][0] = 0;
        }
        for (int i = 0; i <= m; i++) {
            // Base cases
            dp[0][i] = 0;
        }

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                // Dp transitions
                int check = 0;
                if(s.charAt(i - 1) == t.charAt(j - 1)) {
                    check = 1;
                }
                dp[i][j] = Math.max(Math.max(dp[i - 1][j], dp[i][j - 1]), check + dp[i - 1][j - 1]);
            }
        }

        System.out.println(dp[n][m]);
    }
}
